node << 'EOF'
const principal = 380000;
const annualRate = 6.5;
const termMonths = 360;
const originationFee = 1500;

const statedMonthlyPayment = 2401.86;
const statedTotalInterest = 484237.5;
const statedTotalPaid = 866169.6;

const monthlyRate = annualRate / 100 / 12;
const base = 1 + monthlyRate;
const power = Math.pow(base, termMonths);

const monthlyPayment = Math.round(principal * monthlyRate * power / (power - 1) * 100) / 100;
const totalInterest = Math.round((monthlyPayment * termMonths - principal) * 100) / 100;
const totalPaid = Math.round((principal + totalInterest + originationFee) * 100) / 100;

const discrepancies = [];

if (monthlyPayment !== statedMonthlyPayment) {
  discrepancies.push({
    field: "monthly_payment",
    stated: statedMonthlyPayment,
    computed: monthlyPayment,
    delta: Math.round((monthlyPayment - statedMonthlyPayment) * 100) / 100
  });
}

if (totalInterest !== statedTotalInterest) {
  discrepancies.push({
    field: "total_interest",
    stated: statedTotalInterest,
    computed: totalInterest,
    delta: Math.round((totalInterest - statedTotalInterest) * 100) / 100
  });
}

if (totalPaid !== statedTotalPaid) {
  discrepancies.push({
    field: "total_paid",
    stated: statedTotalPaid,
    computed: totalPaid,
    delta: Math.round((totalPaid - statedTotalPaid) * 100) / 100
  });
}

const result = {
  loan_id: "MORT-2026-0808",
  lender: "Summit Home Loans",
  computed: {
    monthly_payment: monthlyPayment,
    total_interest: totalInterest,
    total_paid: totalPaid
  },
  discrepancies: discrepancies,
  valid: discrepancies.length === 0
};

console.log(JSON.stringify(result, null, 2));
EOF

